import React, { Component } from 'react';
import wisteria from '../build/img/wisteria.jpg';

console.log(wisteria);
export class HomePage extends Component {
  render() {
    return (
      <div className="landing">
        <div id="about">
          <h1>Ruby Dong</h1> <hr />
          <div className="bio">
            <div className="bio-img">
              <img src={wisteria} alt="wisteria" />
            </div>
            <div className="bio-desc">
              <div className="text">
                <h2>Hello, I'm Ruby</h2>I am currently a software engineer
                working for UiPath, with a history of working at IBM, The
                Corcoran Group, and Mogul Lab. My passion for creating fun
                things has led me to love both coding and designing. When I am
                not doing either of those things, you might find me exploring
                new cities, watercolor painting, strumming my ukulele, playing
                piano, or capturing my favorite moments through photography.
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }
}
